CREATE TABLE `mall_merchant` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(64) NOT NULL COMMENT '摊位名称',
  `slogan` varchar(100) DEFAULT NULL COMMENT '商品标语',
  `address` varchar(255) DEFAULT NULL COMMENT '摊位地址',
  `address_abbr` varchar(32) DEFAULT NULL COMMENT '地址简称',
  `phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `open_time` varchar(32) DEFAULT NULL COMMENT '营业时段 如18:00-01:00',
