  `cover_img` varchar(255) DEFAULT NULL COMMENT '封面图URL',
  `score` varchar(20) DEFAULT NULL COMMENT '评分',
  `comment_num` int(11) DEFAULT '0' COMMENT '评论数',
  `category` varchar(32) DEFAULT NULL COMMENT '经营类别',
  `distance_km` varchar(32) DEFAULT NULL COMMENT '距离(km)',
  `parking` varchar(32) DEFAULT '0' COMMENT '停车便利',
  `open_day` varchar(10) DEFAULT '0' COMMENT '24小时营业',
  `rank_text` varchar(64) DEFAULT NULL COMMENT '榜单描述',
  `delivery_type` varchar(10) DEFAULT '外卖' COMMENT '到店/外卖/其他',
  `merchant_logo` varchar(255) DEFAULT NULL COMMENT '商位logo（URL或路径）',
  `is_hide` tinyint(1) DEFAULT '0' COMMENT '是否隐藏 1是 0否',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '逻辑删除 0未删 1已删',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`),
  KEY `idx_category` (`category`),
  KEY `idx_distance` (`distance_km`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COMMENT='商位表';

