-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_album`;

CREATE TABLE `sta_album` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `league_id` bigint(20) NOT NULL COMMENT '联赛ID',
  `album_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '相册名称',
  `album_permission` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '相册权限',
  `parent_album_id` bigint(20) DEFAULT NULL COMMENT '所属相册ID',
  `photo_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '照片路径',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='相册管理表';

