-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_enroll`;

CREATE TABLE `sta_enroll` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '自动增长的主键',
  `start_date` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报名开始日期',
  `end_date` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报名结束日期',
  `teams` int(11) DEFAULT NULL COMMENT '球队数量',
  `capacity` int(11) DEFAULT NULL COMMENT '人数限制',
  `contact` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报名联系人',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联系人电话',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联系人电子邮件',
  `instructions` text COLLATE utf8mb4_unicode_ci COMMENT '报名说明',
  `league_id` int(11) NOT NULL COMMENT '联赛ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '记录创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '记录最后更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='报名信息表';

