-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_game`;

CREATE TABLE `sta_game` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `home_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主队名称',
  `away_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客队名称',
  `game_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '比赛类型',
  `homeid` bigint(20) DEFAULT NULL COMMENT '主队id',
  `awayid` bigint(20) DEFAULT NULL COMMENT '客队id',
  `hteam_score` int(11) DEFAULT '0' COMMENT '主队分数',
  `vteam_score` int(11) DEFAULT '0' COMMENT '客队分数',
  `league_id` int(11) DEFAULT NULL COMMENT '联赛id',
  `playing_time` datetime DEFAULT NULL COMMENT '比赛时间',
  `game_round` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '比赛轮次',
  `game_addr` int(255) DEFAULT NULL COMMENT '比赛场地id',
  `venue_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '比赛场地',
  `game_status` int(50) DEFAULT '0' COMMENT '比赛状态',
  `game_stage` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '比赛阶段',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `home_color` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主队颜色',
  `away_color` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客队颜色',
  `home_paused` int(11) DEFAULT NULL COMMENT '主队暂停',
  `away_paused` int(11) DEFAULT NULL COMMENT '客队暂停',
  `home_fouls` int(11) DEFAULT NULL COMMENT '主队犯规',
  `away_fouls` int(11) DEFAULT NULL COMMENT '客队犯规',
  `hsessions_score` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主队每节得分',
  `asessions_score` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客队每节得分',
  PRIMARY KEY (`id`)
