DROP TABLE IF EXISTS `sta_game_address`;

CREATE TABLE `sta_game_address` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `league_id` int(100) DEFAULT NULL COMMENT '联赛id',
  `venue_name` varchar(255) DEFAULT NULL COMMENT '球馆名',
