DROP TABLE IF EXISTS `sta_league_match`;

CREATE TABLE `sta_league_match` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `league_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联赛名称',
  `league_logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联赛Logo',
  `league_nature` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联赛性质',
  `enroll_team` int(11) DEFAULT NULL COMMENT '报名队伍数',
  `host` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主办方',
  `organizer` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '承办方',
  `co_organizer` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '协办方',
  `sponsor` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '赞助商',
  `title_sponsor` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '冠名赞助商',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT '备注',
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '举办地点',
  `league_status` char(11) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联赛状态',
  `enroll_starttime` datetime DEFAULT NULL COMMENT '报名开始时间',
  `enroll_endtime` datetime DEFAULT NULL COMMENT '报名结束时间',
  `game_starttime` datetime DEFAULT NULL COMMENT '比赛开始时间',
  `game_endtime` datetime DEFAULT NULL COMMENT '比赛结束时间',
  `contact_person` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '赛事联系人',
  `contact_phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '赛事联系人电话',
  `background_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '赛事背景图',
  `venue` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '比赛场地',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='联赛表';

