DROP TABLE IF EXISTS `sta_league_rule`;

CREATE TABLE `sta_league_rule` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `leagueid` bigint(20) DEFAULT NULL COMMENT '联赛id',
  `fmt` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '人制',
  `sys` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '赛制',
  `age_lim` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '年龄限制',
  `periods` int(11) DEFAULT NULL COMMENT '节数',
  `period_dur` int(11) DEFAULT NULL COMMENT '单节时长',
  `ot_dur` int(11) DEFAULT NULL COMMENT '加时赛单节时长',
  `rank_rules` text COLLATE utf8mb4_unicode_ci COMMENT '排名规则',
  `win_pts` int(11) DEFAULT NULL COMMENT '胜一场得分',
  `loss_pts` int(11) DEFAULT NULL COMMENT '负一场得分',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
