DROP TABLE IF EXISTS `sta_player`;

CREATE TABLE `sta_player` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '球员ID',
  `team_id` bigint(20) NOT NULL COMMENT '所属球队ID',
  `logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球员logo',
  `name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球员姓名',
  `jersey_number` int(11) NOT NULL COMMENT '球衣号码',
  `weight` double DEFAULT NULL COMMENT '体重 (kg)',
  `height` double DEFAULT NULL COMMENT '身高 (cm)',
  `position` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '位置',
  `phone_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '手机号',
  `create_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=270 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='球员信息表';

