-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_player_ranking`;

CREATE TABLE `sta_player_ranking` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `league_id` bigint(20) NOT NULL,
  `player_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `score` int(11) DEFAULT '0',
  `fouls` int(11) DEFAULT '0',
  `player_logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `starter_count` int(11) DEFAULT '0',
  `games_played` int(11) DEFAULT '0',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='球员榜';

