-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_player_statistic`;

CREATE TABLE `sta_player_statistic` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `player_id` bigint(100) DEFAULT NULL COMMENT '球员id',
  `compeid` bigint(20) DEFAULT NULL COMMENT '比赛id',
  `score` bigint(20) DEFAULT NULL COMMENT '得分',
  `backboard` bigint(20) DEFAULT NULL COMMENT '篮板',
  `assist` bigint(20) DEFAULT NULL COMMENT '助攻',
  `tackle` bigint(20) DEFAULT NULL COMMENT '抢断',
  `cover` bigint(20) DEFAULT NULL COMMENT '盖帽',
  `shoot_the_ball` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '两分球',
  `shoot` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '投篮',
  `trisection` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '三分球',
  `free_throw` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '罚球',
  `block_shot` bigint(20) DEFAULT NULL COMMENT '快攻',
  `mistake` bigint(20) DEFAULT NULL COMMENT '失误',
  `foul` bigint(20) DEFAULT NULL COMMENT '犯规',
  `hit_rate` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '命中率',
  `team_id` bigint(20) DEFAULT NULL COMMENT '球队id',
  `name_num` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球员姓名',
  `jersey_number` int(11) DEFAULT NULL COMMENT '球员号码',
  `homeid` bigint(20) DEFAULT NULL COMMENT '主队id',
  `awayid` bigint(20) DEFAULT NULL COMMENT '客队id',
  `hteam_score` int(11) DEFAULT NULL COMMENT '主队分数',
  `vteam_score` int(11) DEFAULT NULL COMMENT '客队分数',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1313 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='数据统计表';

