-- 删除表（如果存在）
DROP TABLE IF EXISTS `sta_referee_info`;

CREATE TABLE `sta_referee_info` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(64) NOT NULL COMMENT '姓名',
  `avatar` varchar(255) DEFAULT NULL COMMENT '裁判头像',
  `level` varchar(32) DEFAULT NULL COMMENT '等级',
  `cert_date` date DEFAULT NULL COMMENT '获证日期',
  `reg_unit` varchar(128) DEFAULT NULL COMMENT '注册单位',
  `signature` varchar(255) DEFAULT NULL COMMENT '个性签名',
  `status` char(1) DEFAULT '1' COMMENT '状态 1正常 0停用',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `order_count` int(11) DEFAULT '0' COMMENT '订单数',
  `schedule_log` text COMMENT '排班记录(JSON)',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `referee_years` int(11) DEFAULT '0' COMMENT '执裁年限(年)',
  `price` varchar(32) DEFAULT '0' COMMENT '价格(字符串)',
  `avatar_path` varchar(255) DEFAULT NULL COMMENT '头像路径',
  `referee_resume` text COMMENT '执裁履历',
  `overall_rating` varchar(10) DEFAULT NULL COMMENT '综合评价',
  `praise_rate` double DEFAULT NULL COMMENT '好评率',
  `is_hide` tinyint(1) DEFAULT '0' COMMENT '是否隐藏 0否 1是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COMMENT='裁判信息表';

