DROP TABLE IF EXISTS `sta_team`;

CREATE TABLE `sta_team` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `team_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球队名称',
  `team_logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球队logo',
  `team_photo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球队合照',
  `leader_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '领队',
  `leader_phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '领队电话',
  `city` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属城市',
  `home_color` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主场颜色',
  `away_color` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客场颜色',
  `team_introduction` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球队简介',
  `attendance` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '出勤',
  `time_slot` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '时间段',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `game_order_count` int(11) DEFAULT '0' COMMENT '约赛成单总场次',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=94 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='球队信息表';

