DROP TABLE IF EXISTS `sta_team_ranking`;

CREATE TABLE `sta_team_ranking` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `league_id` bigint(20) NOT NULL COMMENT '联赛ID',
  `team_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '球队名',
  `team_logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '球队logo',
  `score` int(11) DEFAULT '0' COMMENT '得分',
  `conceded` int(11) DEFAULT '0' COMMENT '失分',
  `wins` int(11) DEFAULT '0' COMMENT '胜场',
  `losses` int(11) DEFAULT '0' COMMENT '负场',
  `games_played` int(11) DEFAULT '0' COMMENT '比赛场数',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='球队榜';

